using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords =
    [
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","can","could","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","during",
        "before","after","above","below","up","down","out","off","over","under",
        "this","that","these","those","it","its","i","me","my","we","our","you",
        "your","he","him","his","she","her","they","them","their","not","no","so",
        "if","then","than","too","very","just","also","more","most","such","each"
    ];

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences, preserving original order.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = topIndices.Count
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary().Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                var lower = word.ToLowerInvariant();
                if (StopWords.Contains(lower) || lower.Length < 2)
                    continue;

                freq[lower] = freq.GetValueOrDefault(lower) + 1;
            }
        }

        // Normalize by the maximum frequency.
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys)
                freq[key] /= max;
        }

        return freq;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            double score = words.Sum(w => wordFrequencies.GetValueOrDefault(w.ToLowerInvariant()));
            // Normalize by word count to avoid bias toward longer sentences.
            scores.Add(words.Length > 0 ? score / words.Length : 0);
        }

        return scores;
    }

    private static string[] Tokenize(string text) =>
        WordToken().Matches(text).Select(m => m.Value).ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordToken();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummaryService summaryService) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = summaryService.Summarize(request.Text, request.MaxSentences);
        return Ok(result);
    }
}

